+    const embBuf = new ArrayBuffer(64);
+    const embView = new DataView(embBuf);
+    const vecs = [
+      [1, 0, 0, 0],  // Row 0: distance to query [1,0,0,0] = 0
+      [0, 1, 0, 0],  // Row 1: distance = 2
