+
+    // Also include a scalar column
+    const idBuf = new ArrayBuffer(16);
+    const idView = new DataView(idBuf);
+    for (let i = 0; i < 4; i++) idView.setInt32(i * 4, i + 1, true);
+
+    const cols: ColumnMeta[] = [
+      {
