+    if ((byte & 0x80) === 0) {
+      return { value: result, bytesRead: pos - offset };
+    }
+
+    shift += 7;
+    if (shift >= 35) {
+      return { value: result, bytesRead: pos - offset };
+    }
+  }
+
+  return { value: result, bytesRead: pos - offset };
+}
