+    2: "int32",
+    3: "int64",
+    4: "uint8",
+    5: "uint16",
+    6: "uint32",
+    7: "uint64",
+    8: "float16",
+    9: "float32",
+    10: "float64",
+    11: "utf8",
+    12: "binary",
+    13: "bool",
+    14: "fixed_size_list",
+  };
+  return types[value] ?? "int64";
+}

