+    let meta: TableMeta | undefined = this.footerCache.get(query.table);
+    if (!meta) {
+      meta = (await this.loadTableFromR2(query.table)) ?? undefined;
+      if (!meta) return this.json({ error: `Table "${query.table}" not found` }, 404);
+    }
