+  const columns: { name: string; type: number }[] = [];
+  let pos = 28;
+  for (let c = 0; c < numColumns; c++) {
+    const nameLen = buf[pos++];
+    const name = textDecoder.decode(buf.subarray(pos, pos + nameLen)); pos += nameLen;
+    columns.push({ name, type: buf[pos++] });
+  }
